// Google Places Lead Scraper for Markexis
// Finds LatAm B2B companies using Google Places Text Search API
// POST body (optional): { city, query } to run a single custom search
// No body: runs the full preset query list

const INGEST_URL = 'http://67.207.89.85:5678/webhook/lead-ingest';
const PLACES_KEY = $env.GOOGLE_PLACES_API_KEY;
const CAP = 25; // max leads per run (Places API: ~4k/mo free)

// Pre-defined searches: B2B companies in LatAm cities that Markexis serves
const DEFAULT_QUERIES = [
  { query: 'B2B software company', city: 'Mexico City', lat: 19.4326, lng: -99.1332 },
  { query: 'SaaS startup technology', city: 'Sao Paulo', lat: -23.5505, lng: -46.6333 },
  { query: 'technology company B2B', city: 'Bogota', lat: 4.7110, lng: -74.0721 },
  { query: 'marketing agency B2B', city: 'Buenos Aires', lat: -34.6037, lng: -58.3816 },
  { query: 'fintech company', city: 'Mexico City', lat: 19.4326, lng: -99.1332 },
  { query: 'software startup', city: 'Santiago', lat: -33.4489, lng: -70.6693 },
  { query: 'e-commerce B2B platform', city: 'Sao Paulo', lat: -23.5505, lng: -46.6333 },
];

// Override with body params if provided
const body = $input.first()?.json?.body || {};
const queries = (body.city && body.query)
  ? [{ query: body.query, city: body.city, lat: body.lat || 19.4326, lng: body.lng || -99.1332 }]
  : DEFAULT_QUERIES;

const seen = new Set();
const results = [];

for (const q of queries) {
  if (results.length >= CAP) break;

  // Text Search API (old stable endpoint — consistent field support)
  let searchRes;
  try {
    searchRes = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://maps.googleapis.com/maps/api/place/textsearch/json?query=${encodeURIComponent(q.query + ' ' + q.city)}&key=${PLACES_KEY}&type=establishment`,
    });
  } catch (e) {
    continue;
  }

  if (searchRes.status !== 'OK' && searchRes.status !== 'ZERO_RESULTS') {
    continue;
  }

  for (const place of (searchRes.results || []).slice(0, 5)) {
    if (results.length >= CAP) break;
    if (seen.has(place.place_id)) continue;
    seen.add(place.place_id);

    // Skip obvious non-B2B categories
    const types = place.types || [];
    const skipTypes = ['restaurant', 'food', 'lodging', 'gas_station', 'hospital', 'school', 'church', 'store', 'supermarket', 'bakery', 'bar', 'cafe'];
    if (skipTypes.some(t => types.includes(t))) continue;

    // Place Details to get website URL
    let website = null;
    let phone = null;
    try {
      const details = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://maps.googleapis.com/maps/api/place/details/json?place_id=${place.place_id}&fields=website,formatted_phone_number&key=${PLACES_KEY}`,
      });
      website = details.result?.website || null;
      phone = details.result?.formatted_phone_number || null;
    } catch (e) { /* details optional */ }

    // Derive domain from website
    let domain = null;
    if (website) {
      try {
        const u = new URL(website);
        domain = u.hostname.replace(/^www\./, '');
      } catch (e) { /* invalid URL */ }
    }

    const address = place.formatted_address || '';
    const lead = {
      name: place.name,
      email: null,
      company: place.name,
      domain: domain,
      title: null,
      location: q.city,
      source_platform: 'google_maps',
      source_url: website || `https://maps.google.com/?cid=${place.place_id}`,
      raw_bio: `${place.name} — ${address}. Types: ${types.slice(0, 3).join(', ')}. Found via Places search: "${q.query}" in ${q.city}.`,
      company_size_signal: 'unknown',
      scraped_at: new Date().toISOString(),
    };

    let ingestResult = 'skipped';
    try {
      const r = await this.helpers.httpRequest({
        method: 'POST',
        url: INGEST_URL,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(lead),
      });
      ingestResult = r.status || 'ok';
    } catch (e) {
      ingestResult = `error: ${e.message.slice(0, 80)}`;
    }

    results.push({ name: place.name, domain, city: q.city, ingest: ingestResult });

    // 200ms between detail calls to stay under Places rate limit
    await new Promise(r => setTimeout(r, 200));
  }
}

return [{ json: { scraped: results.length, results } }];
